"""Bookstore data models."""
from dataclasses import dataclass, asdict
from typing import Dict, List, Optional


@dataclass
class Book:
    id: int
    title: str
    author: str
    genre: str
    price: float

    def to_dict(self):
        return asdict(self)


class BookStore:
    """In-memory book store."""

    def __init__(self):
        self._books: Dict[int, Book] = {}
        self._next_id: int = 1
        self._seed()

    def _seed(self):
        """Add initial books for testing."""
        seed_data = [
            ("The Great Gatsby", "F. Scott Fitzgerald", "fiction", 12.99),
            ("Gatsby Revisited", "F. Scott Fitzgerald", "fiction", 14.99),
            ("Python Crash Course", "Eric Matthes", "technology", 29.99),
            ("Clean Code", "Robert Martin", "technology", 34.99),
            ("Dune", "Frank Herbert", "science_fiction", 15.99),
            ("Foundation", "Isaac Asimov", "science_fiction", 13.99),
        ]
        for title, author, genre, price in seed_data:
            book = Book(
                id=self._next_id,
                title=title,
                author=author,
                genre=genre,
                price=price,
            )
            self._books[book.id] = book
            self._next_id += 1

    def get_all(self, genre: Optional[str] = None) -> List[Book]:
        """Return all books, optionally filtered by genre."""
        books = list(self._books.values())
        if genre:
            books = [b for b in books if b.genre == genre]
        return books

    def get_by_id(self, book_id: int) -> Optional[Book]:
        """Return a book by ID or None."""
        return self._books.get(book_id)

    def search(self, query: str) -> List[Book]:
        """Search books by title (case-insensitive substring match)."""
        query_lower = query.lower()
        # BUG: inverted condition — returns books that do NOT match
        return [b for b in self._books.values()
                if query_lower not in b.title.lower()]

