"""Business logic handlers for the Bookstore API."""
from models import BookStore


# --- Pricing functions (should eventually live in their own module) ---

def discount_price(price, percent):
    """Apply a percentage discount to a price.
    Example: discount_price(100, 10) should return 90.0
    """
    # BUG: applies discount twice instead of once
    factor = 1 - percent / 100
    return round(price * factor * factor, 2)


def bulk_price(unit_price, quantity, bulk_threshold=10, bulk_discount=5):
    """Calculate total price for a quantity of items.
    If quantity >= bulk_threshold, apply bulk_discount percent off each unit.
    """
    if quantity >= bulk_threshold:
        unit = discount_price(unit_price, bulk_discount)
    else:
        unit = unit_price
    return round(unit * quantity, 2)


def format_price(price):
    """Format a price as a string like '$12.99'."""
    return f"${price:.2f}"


# --- Handler class ---

class BookHandler:
    def __init__(self, store: BookStore):
        self.store = store

    def list_books(self, genre=None):
        """Return (books_list, status_code)."""
        books = self.store.get_all(genre=genre)
        return [b.to_dict() for b in books], 200

    def get_book(self, book_id):
        """Return (book_dict, status_code) or (error, 404)."""
        book = self.store.get_by_id(book_id)
        if book is None:
            return {"error": "Book not found"}, 404
        return book.to_dict(), 200

    def search_books(self, query):
        """Return (books_list, status_code)."""
        books = self.store.search(query)
        return [b.to_dict() for b in books], 200

    def get_discount(self, price, percent):
        """Get discounted price."""
        return discount_price(price, percent)

    def get_bulk_price(self, unit_price, quantity):
        """Get bulk price."""
        return bulk_price(unit_price, quantity)

    def get_formatted_price(self, price):
        """Get formatted price string."""
        return format_price(price)

    def get_price_info(self, book_id, discount_pct=0, quantity=1):
        """Return (price_info_dict, status_code) or (error, 404)."""
        book = self.store.get_by_id(book_id)
        if book is None:
            return {"error": "Book not found"}, 404
        unit = book.price
        if discount_pct > 0:
            unit = self.get_discount(unit, discount_pct)
        total = self.get_bulk_price(unit, quantity)
        return {
            "book_id": book_id,
            "unit_price": unit,
            "quantity": quantity,
            "total": total,
            "formatted_total": self.get_formatted_price(total),
        }, 200

